+import { $internal } from '../common';
+import type { Trait } from '../trait/types';
+import type { Aspect, AspectConstituent } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return (value as Aspect | undefined)?.__aspect === true;
+}
+
+export function createAspect<const T extends readonly [AspectConstituent, AspectConstituent, ...AspectConstituent[]]>(
+    ...constituents: T
+): Aspect {
+    const traits: Trait[] = [];
+    for (const constituent of constituents) {
+        if (isAspect(constituent)) traits.push(...constituent.traits);
+        else traits.push(constituent);
+    }
+
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (trait[$internal].relation) {
+            throw new Error('Aspects cannot contain relation traits');
+        }
+        const traitSchema = trait.schema;
+        if (typeof traitSchema === 'function') {
+            throw new Error('Aspects cannot contain AoS traits');
+        }
+        for (const field of Object.keys(traitSchema)) {
+            if (fields.has(field)) {
+                throw new Error(`Aspect traits cannot share the field "${field}"`);
+            }
+            fields.add(field);
+            schema[field] = traitSchema[field];
+        }
+    }
+
+    return Object.freeze({
+        id: aspectId++,
+        traits: Object.freeze(traits.slice()),
+        schema: Object.freeze(schema),
+        __aspect: true as const,
+    });
+}
